import { useState, useEffect } from 'react';
import { Container, Nav } from 'react-bootstrap';
import SetList from './components/SetList';
import CardCreator from './components/CardCreator';
import FlashcardView from './components/FlashcardView';
import './App.css';

function App() {
  const [view, setView] = useState('home');
  const [sets, setSets] = useState([]);
  const [currentSet, setCurrentSet] = useState(null);

  const fetchSets = async () => {
    try {
      const res = await fetch('/api/sets');
      const data = await res.json();
      setSets(data);
    } catch (err) {
      console.error('Failed to fetch sets:', err);
    }
  };

  useEffect(() => {
    fetchSets();
  }, []);

  const handleSelectSet = async (setId) => {
    try {
      const res = await fetch(`/api/sets/${setId}`);
      const data = await res.json();
      setCurrentSet(data);
      setView('review');
    } catch (err) {
      console.error('Failed to fetch set:', err);
    }
  };

  const handleDeleteSet = async (setId) => {
    try {
      await fetch(`/api/sets/${setId}`, { method: 'DELETE' });
      fetchSets();
      if (currentSet && currentSet.id === setId) {
        setCurrentSet(null);
        setView('home');
      }
    } catch (err) {
      console.error('Failed to delete set:', err);
    }
  };

  const handleSetSaved = () => {
    fetchSets();
    setView('home');
  };

  return (
    <div className="min-vh-100 bg-light">
      <Container className="py-4">
        <h1 className="text-center mb-4">Memory Card Generator</h1>
        <Nav
          variant="tabs"
          className="justify-content-center mb-4"
          activeKey={view === 'review' ? 'review' : view}
          onSelect={(key) => {
            if (key === 'create') setView('create');
            else if (key === 'home') {
              setView('home');
              setCurrentSet(null);
            }
          }}
        >
          <Nav.Item>
            <Nav.Link eventKey="home">My Sets</Nav.Link>
          </Nav.Item>
          <Nav.Item>
            <Nav.Link eventKey="create">Create New Set</Nav.Link>
          </Nav.Item>
        </Nav>

        {view === 'home' && (
          <SetList
            sets={sets}
            onSelect={handleSelectSet}
            onDelete={handleDeleteSet}
            onCreateNew={() => setView('create')}
          />
        )}
        {view === 'create' && <CardCreator onSaved={handleSetSaved} />}
        {view === 'review' && currentSet && (
          <FlashcardView set={currentSet} onBack={() => { setCurrentSet(null); setView('home'); }} />
        )}
      </Container>
    </div>
  );
}

export default App;
